function Badge({ count, show = false }: { count: number; show?: boolean }) {
  return <>{show && <span>{count}</span>}</>;
}

<Badge count={0} show={true} />

Code này output gì?

function Item({ id, name }: { id: number; name: string }) {
  return <li key={id}>{name}</li>;
}

function List() {
  const items = [{ id: 1, name: 'Alpha' }, { id: 2, name: 'Beta' }];
  return (
    <ul>
      {items.map(item => <Item {...item} key={item.id} />)}
    </ul>
  );
}

Output của render này là gì?

function Row({ id }: { id: number }) {
  return <tr><td>{id}</td></tr>;
}

function Table() {
  return (
    <table>
      {[{ id: 1 }, { id: 2 }].map(item => (
        <React.Fragment key={item.id}>
          <Row id={item.id} />
        </React.Fragment>
      ))}
    </table>
  );
}

